const data = $('Switch4').first().json.message;
const accounts = data.accounts;

const rawMarcados = $('loginsMarcadosProduccion2').first().json.propertyName;
const listaLogins = JSON.parse(rawMarcados).map(l => String(l));

const removedLogins = (data.removed_logins ?? []).map(l => String(l));

// Snapshot de Redis — todas las keys pos:login:position_id activas
const rawSnapshot = $('Redis_Snapshot').first().json;
const redisKeys = Object.keys(rawSnapshot).filter(k => k.startsWith('pos:'));

const symbolsAllowed = [
  "BearX1000.","BearX400.","BearX500.","BearX777.","BearX900.",
  "BullX1000.","BullX400.","BullX500.","BullX777.","BullX900.",
  "EmasVol10","EmasVol100","EmasVol20","EmasVol30","EmasVol40",
  "EmasVol50","EmasVol60","EmasVol70","EmasVol80","EmasVol90",
  "FomoX111.","FomoX333.","FomoX555.","FomoX888.","FomoX999.",
  "FomoXpeed100.","Fortune100.","Fortune1000.","Fortune250.",
  "Fortune500.","FortuneX200.","FortuneX300.","FortuneX500.",
  "LionX100","LionX120","LionX150","LionX200","LionX25",
  "LionX40","LionX50","LionX60","LionX75","LionX90",
  "VorteX100.","VorteX20.","VorteX40.","VorteX60.","VorteX80.",
  "XpeedDown200","XpeedDown300","XpeedUp200","XpeedUp300"
];

const VENTANA_SEGUNDOS = 15;
const ahoraEnSegundos = Math.floor(data.timestamp_msc / 1000);

// ── OPEN ──────────────────────────────────────────────────────────────────────
const cuentasMarcadas = accounts
  .filter(account => listaLogins.includes(String(account.login)))
  .flatMap(account => {
    const positionsFiltradas = (account.positions ?? []).filter(position => {
      const diff = ahoraEnSegundos - position.time_create;
      return diff >= 0 && diff <= VENTANA_SEGUNDOS && symbolsAllowed.includes(position.symbol);
    });
    return positionsFiltradas.map(position => ({
      json: {
        login: String(account.login),
        name: account.name,
        estado: "OPEN",
        direccion: position.action,
        position_id: position.ticket,
        symbol: position.symbol,
        volume: position.volume,
        time_create: position.time_create
      }
    }));
  });

// ── CLOSE por removed_logins ──────────────────────────────────────────────────
const cuentasEliminadas = removedLogins
  .filter(login => listaLogins.includes(login))
  .map(login => ({
    json: { login, estado: "CLOSE" }
  }));

// ── CLOSE parcial — posición desapareció del WS pero login sigue activo ───────
// Set de todas las posiciones activas en este mensaje: "pos:login:position_id"
const posicionesActivasEnWS = new Set(
  accounts
    .filter(account => listaLogins.includes(String(account.login)))
    .flatMap(account =>
      (account.positions ?? []).map(p =>
        "pos:" + String(account.login) + ":" + String(p.ticket)
      )
    )
);

const cierresParciales = redisKeys
  .filter(key => {
    const parts = key.split(':');
    const loginDeKey = parts[1];
    // El login sigue en el WS (no está en removed_logins)
    // pero esta posición específica ya no aparece en su array positions
    const loginSigueEnWS = accounts.some(a => String(a.login) === loginDeKey);
    const loginEstaEnRemoved = removedLogins.includes(loginDeKey);
    return loginSigueEnWS && !loginEstaEnRemoved && !posicionesActivasEnWS.has(key);
  })
  .map(key => {
    const parts = key.split(':');
    const loginDeKey = parts[1];
    return {
      json: {
        login: loginDeKey,
        estado: "CLOSE"
      }
    };
  });

return [...cuentasMarcadas, ...cuentasEliminadas, ...cierresParciales];

// Code_DedupOpen — versión final correcta
const redisResult = $input.all(); // array de items, uno por posición

return redisResult
  .map((redisItem, index) => {
    const propertyName = redisItem.json.propertyName ?? null;

    // Si ya existe en Redis → duplicado, ignorar este item
    if (propertyName) return null;

    // Recuperar el item original del Switch3 por índice
    const originalItem = $('Switch3').all()[index]?.json;
    if (!originalItem) return null;

    return { json: { ...originalItem } };
  })
  .filter(item => item !== null);

// Toma los CLOSE que vienen del Switch3
const closeItems = $input.all();

// Reutiliza el snapshot que ya se leyó al inicio
const rawSnapshot = $('Redis_Snapshot').first().json;

// Agrupa por login usando solo los logins en CLOSE
const byLogin = {};

for (const item of closeItems) {
  const loginCierre = String(item.json.login);

  // Filtrar el snapshot por este login
  for (const [key, rawValue] of Object.entries(rawSnapshot)) {
    if (!key.startsWith('pos:')) continue;

    const parts = key.split(':');
    const loginDeKey = parts[1];
    if (loginDeKey !== loginCierre) continue;

    const redisData = JSON.parse(rawValue);

    if (!byLogin[loginCierre]) {
      byLogin[loginCierre] = {
        login: loginCierre,
        unix_stamp: redisData.unix_stamp,
        positions: []
      };
    } else if (redisData.unix_stamp < byLogin[loginCierre].unix_stamp) {
      byLogin[loginCierre].unix_stamp = redisData.unix_stamp;
    }

    byLogin[loginCierre].positions.push({
      key,
      position_id: String(redisData.position_id),
      symbol: redisData.symbol
    });
  }
}

return Object.values(byLogin).map(entry => ({ json: entry }));

const allResponses = $input.all();
const allPrev = $('Code in JavaScript6').all();

return allResponses.flatMap((responseItem, index) => {
  const orders = responseItem.json.orders ?? [];
  const prev = allPrev[index]?.json;
  if (!prev) return [];

  const { login, positions } = prev;

  // Para cada posición que mandamos a verificar, buscar en la respuesta
  return positions.flatMap(pos => {
    const order = orders.find(o => String(o.position_id) === String(pos.position_id));

    // No encontrada o sigue abierta → ignorar
    if (!order) return [];
    if (order.time_close === 0 || order.time_close === null) return [];

    return [{
      json: {
        login,
        position_id:   String(pos.position_id),
        symbol:        order.deal_internal_out?.symbol ?? order.symbol ?? pos.symbol,
        volume:        order.deal_internal_out?.lots ?? order.lots,
        estado_cierre: "CONFIRMADO",
        key:           pos.key
      }
    }];
  });
});

// Code in JavaScript6 — merge bearer con el grupo agrupado por login
const allBearer = $input.all();
const allPrev = $('Code in JavaScript5').all();

return allBearer.map((bearerItem, index) => {
  const bearerToken = bearerItem.json.bearerToken;
  const prev = allPrev[index]?.json;
  if (!prev) return null;
  return {
    json: {
      login:      prev.login,
      unix_stamp: prev.unix_stamp,
      positions:  prev.positions,   // ← array completo de posiciones del login
      bearerToken
    }
  };
}).filter(Boolean);

